// ─── Radar Chart ─────────────────────────────────────────────────────────────

function RadarChart({ dimensions }: { dimensions: DimensionScore[] }) {
                        const size = 320;
                        const cx = size / 2;
                        const cy = size / 2;
                        const maxR = 130;
                        const n = dimensions.length;

                        const angle = (i: number) => (Math.PI * 2 * i) / n - Math.PI / 2;
                        const pt = (i: number, r: number) => ({
                                                x: cx + r * Math.cos(angle(i)),
                                                y: cy + r * Math.sin(angle(i)),
                        });

                        // Grid rings
                        const rings = [20, 40, 60, 80, 100];

                        // Score polygon
                        const scorePts = dimensions.map((d, i) => {
                                                const r = (d.score / 100) * maxR;
                                                const p = pt(i, r);
                                                return `${p.x},${p.y}`;
                        });

                        return (
                                                <svg
                                                                        width={size}
                                                                        height={size}
                                                                        className="drop-shadow-lg"
                                                >
                                                                        {/* Grid rings */}
                                                                        {rings.map((ring) => {
                                                                                                const r =
                                                                                                                        (ring /
                                                                                                                                                100) *
                                                                                                                        maxR;
                                                                                                const pts =
                                                                                                                        Array.from(
                                                                                                                                                {
                                                                                                                                                                        length: n,
                                                                                                                                                },
                                                                                                                                                (
                                                                                                                                                                        _,
                                                                                                                                                                        i
                                                                                                                                                ) => {
                                                                                                                                                                        const p =
                                                                                                                                                                                                pt(
                                                                                                                                                                                                                        i,
                                                                                                                                                                                                                        r
                                                                                                                                                                                                );
                                                                                                                                                                        return `${p.x},${p.y}`;
                                                                                                                                                }
                                                                                                                        ).join(
                                                                                                                                                ' '
                                                                                                                        );
                                                                                                return (
                                                                                                                        <polygon
                                                                                                                                                key={
                                                                                                                                                                        ring
                                                                                                                                                }
                                                                                                                                                points={
                                                                                                                                                                        pts
                                                                                                                                                }
                                                                                                                                                fill="none"
                                                                                                                                                stroke="rgba(255,255,255,0.08)"
                                                                                                                                                strokeWidth="1"
                                                                                                                        />
                                                                                                );
                                                                        })}

                                                                        {/* Axis lines */}
                                                                        {dimensions.map((_, i) => {
                                                                                                const outer =
                                                                                                                        pt(
                                                                                                                                                i,
                                                                                                                                                maxR
                                                                                                                        );
                                                                                                return (
                                                                                                                        <line
                                                                                                                                                key={
                                                                                                                                                                        i
                                                                                                                                                }
                                                                                                                                                x1={
                                                                                                                                                                        cx
                                                                                                                                                }
                                                                                                                                                y1={
                                                                                                                                                                        cy
                                                                                                                                                }
                                                                                                                                                x2={
                                                                                                                                                                        outer.x
                                                                                                                                                }
                                                                                                                                                y2={
                                                                                                                                                                        outer.y
                                                                                                                                                }
                                                                                                                                                stroke="rgba(255,255,255,0.08)"
                                                                                                                                                strokeWidth="1"
                                                                                                                        />
                                                                                                );
                                                                        })}

                                                                        {/* Score polygon fill */}
                                                                        <polygon
                                                                                                points={scorePts.join(
                                                                                                                        ' '
                                                                                                )}
                                                                                                fill="rgba(99,102,241,0.2)"
                                                                                                stroke="rgba(99,102,241,0.7)"
                                                                                                strokeWidth="2"
                                                                                                strokeLinejoin="round"
                                                                        />

                                                                        {/* Score dots */}
                                                                        {dimensions.map((d, i) => {
                                                                                                const r =
                                                                                                                        (d.score /
                                                                                                                                                100) *
                                                                                                                        maxR;
                                                                                                const p =
                                                                                                                        pt(
                                                                                                                                                i,
                                                                                                                                                r
                                                                                                                        );
                                                                                                return (
                                                                                                                        <circle
                                                                                                                                                key={
                                                                                                                                                                        i
                                                                                                                                                }
                                                                                                                                                cx={
                                                                                                                                                                        p.x
                                                                                                                                                }
                                                                                                                                                cy={
                                                                                                                                                                        p.y
                                                                                                                                                }
                                                                                                                                                r={
                                                                                                                                                                        4
                                                                                                                                                }
                                                                                                                                                fill={
                                                                                                                                                                        d.color
                                                                                                                                                }
                                                                                                                                                stroke="white"
                                                                                                                                                strokeWidth="1.5"
                                                                                                                        />
                                                                                                );
                                                                        })}

                                                                        {/* Labels */}
                                                                        {dimensions.map((d, i) => {
                                                                                                const p =
                                                                                                                        pt(
                                                                                                                                                i,
                                                                                                                                                maxR +
                                                                                                                                                                        22
                                                                                                                        );
                                                                                                const anchor =
                                                                                                                        p.x <
                                                                                                                        cx -
                                                                                                                                                5
                                                                                                                                                ? 'end'
                                                                                                                                                : p.x >
                                                                                                                                                    cx +
                                                                                                                                                                            5
                                                                                                                                                  ? 'start'
                                                                                                                                                  : 'middle';
                                                                                                return (
                                                                                                                        <text
                                                                                                                                                key={
                                                                                                                                                                        i
                                                                                                                                                }
                                                                                                                                                x={
                                                                                                                                                                        p.x
                                                                                                                                                }
                                                                                                                                                y={
                                                                                                                                                                        p.y
                                                                                                                                                }
                                                                                                                                                textAnchor={
                                                                                                                                                                        anchor
                                                                                                                                                }
                                                                                                                                                dominantBaseline="middle"
                                                                                                                                                fontSize="10"
                                                                                                                                                fill={
                                                                                                                                                                        d.color
                                                                                                                                                }
                                                                                                                                                fontWeight="600"
                                                                                                                        >
                                                                                                                                                {
                                                                                                                                                                        d.name.split(
                                                                                                                                                                                                ' '
                                                                                                                                                                        )[0]
                                                                                                                                                }
                                                                                                                        </text>
                                                                                                );
                                                                        })}

                                                                        {/* Centre score */}
                                                                        <text
                                                                                                x={
                                                                                                                        cx
                                                                                                }
                                                                                                y={
                                                                                                                        cy -
                                                                                                                        10
                                                                                                }
                                                                                                textAnchor="middle"
                                                                                                dominantBaseline="middle"
                                                                                                fontSize="26"
                                                                                                fill="white"
                                                                                                fontWeight="700"
                                                                        >
                                                                                                {dimensions.length >
                                                                                                0
                                                                                                                        ? Math.round(
                                                                                                                                                  dimensions.reduce(
                                                                                                                                                                          (
                                                                                                                                                                                                  s,
                                                                                                                                                                                                  d
                                                                                                                                                                          ) =>
                                                                                                                                                                                                  s +
                                                                                                                                                                                                  d.score *
                                                                                                                                                                                                                          d.weight,
                                                                                                                                                                          0
                                                                                                                                                  )
                                                                                                                          )
                                                                                                                        : '--'}
                                                                        </text>
                                                                        <text
                                                                                                x={
                                                                                                                        cx
                                                                                                }
                                                                                                y={
                                                                                                                        cy +
                                                                                                                        16
                                                                                                }
                                                                                                textAnchor="middle"
                                                                                                fontSize="11"
                                                                                                fill="rgba(255,255,255,0.5)"
                                                                        >
                                                                                                composite
                                                                        </text>
                                                </svg>
                        );
}

// ─── Mini Trend Sparkline ─────────────────────────────────────────────────────

function Sparkline({ history }: { history: HealthTrendPoint[] }) {
                        if (history.length < 2) {
                                                return (
                                                                        <div className="text-xs text-white/30 italic">
                                                                                                Run
                                                                                                analysis
                                                                                                again
                                                                                                to
                                                                                                see
                                                                                                trends
                                                                        </div>
                                                );
                        }

                        const W = 220;
                        const H = 48;
                        const scores = history.map((h) => h.overall_score);
                        const min = Math.min(...scores) - 5;
                        const max = Math.max(...scores) + 5;
                        const scaleX = (i: number) => (i / (scores.length - 1)) * W;
                        const scaleY = (v: number) => H - ((v - min) / (max - min)) * H;

                        const d = scores
                                                .map(
                                                                        (v, i) =>
                                                                                                `${i === 0 ? 'M' : 'L'} ${scaleX(i)} ${scaleY(v)}`
                                                )
                                                .join(' ');

                        const area =
                                                d +
                                                ` L ${scaleX(scores.length - 1)} ${H} L ${scaleX(0)} ${H} Z`;

                        const lastImproved = scores[scores.length - 1] >= scores[scores.length - 2];

                        return (
                                                <svg
                                                                        width={W}
                                                                        height={H}
                                                                        className="overflow-visible"
                                                >
                                                                        <defs>
                                                                                                <linearGradient
                                                                                                                        id="sparkGrad"
                                                                                                                        x1="0"
                                                                                                                        y1="0"
                                                                                                                        x2="0"
                                                                                                                        y2="1"
                                                                                                >
                                                                                                                        <stop
                                                                                                                                                offset="0%"
                                                                                                                                                stopColor={
                                                                                                                                                                        lastImproved
                                                                                                                                                                                                ? '#10b981'
                                                                                                                                                                                                : '#ef4444'
                                                                                                                                                }
                                                                                                                                                stopOpacity="0.4"
                                                                                                                        />
                                                                                                                        <stop
                                                                                                                                                offset="100%"
                                                                                                                                                stopColor={
                                                                                                                                                                        lastImproved
                                                                                                                                                                                                ? '#10b981'
                                                                                                                                                                                                : '#ef4444'
                                                                                                                                                }
                                                                                                                                                stopOpacity="0"
                                                                                                                        />
                                                                                                </linearGradient>
                                                                        </defs>
                                                                        <path
                                                                                                d={
                                                                                                                        area
                                                                                                }
                                                                                                fill="url(#sparkGrad)"
                                                                        />
                                                                        <path
                                                                                                d={
                                                                                                                        d
                                                                                                }
                                                                                                fill="none"
                                                                                                stroke={
                                                                                                                        lastImproved
                                                                                                                                                ? '#10b981'
                                                                                                                                                : '#ef4444'
                                                                                                }
                                                                                                strokeWidth="2"
                                                                                                strokeLinecap="round"
                                                                                                strokeLinejoin="round"
                                                                        />
                                                </svg>
                        );
}

// ─── Score Ring ───────────────────────────────────────────────────────────────

function ScoreRing({
                        score,
                        grade,
                        status,
                        color,
}: {
                        score: number;
                        grade: string;
                        status: string;
                        color: string;
}) {
                        const r = 80;
                        const circ = 2 * Math.PI * r;
                        const offset = circ - (score / 100) * circ;

                        return (
                                                <div className="relative flex items-center justify-center">
                                                                        {/* Glow effect */}
                                                                        <div
                                                                                                className="absolute rounded-full blur-2xl opacity-30 w-52 h-52"
                                                                                                style={{
                                                                                                                        backgroundColor: color,
                                                                                                }}
                                                                        />
                                                                        <svg
                                                                                                width="200"
                                                                                                height="200"
                                                                                                className="relative drop-shadow-xl"
                                                                        >
                                                                                                {/* Track */}
                                                                                                <circle
                                                                                                                        cx="100"
                                                                                                                        cy="100"
                                                                                                                        r={
                                                                                                                                                r
                                                                                                                        }
                                                                                                                        fill="none"
                                                                                                                        stroke="rgba(255,255,255,0.06)"
                                                                                                                        strokeWidth="16"
                                                                                                />
                                                                                                {/* Progress */}
                                                                                                <circle
                                                                                                                        cx="100"
                                                                                                                        cy="100"
                                                                                                                        r={
                                                                                                                                                r
                                                                                                                        }
                                                                                                                        fill="none"
                                                                                                                        stroke={
                                                                                                                                                color
                                                                                                                        }
                                                                                                                        strokeWidth="16"
                                                                                                                        strokeLinecap="round"
                                                                                                                        strokeDasharray={
                                                                                                                                                circ
                                                                                                                        }
                                                                                                                        strokeDashoffset={
                                                                                                                                                offset
                                                                                                                        }
                                                                                                                        transform="rotate(-90 100 100)"
                                                                                                                        style={{
                                                                                                                                                transition: 'stroke-dashoffset 1.2s ease-out',
                                                                                                                        }}
                                                                                                />
                                                                                                {/* Score text */}
                                                                                                <text
                                                                                                                        x="100"
                                                                                                                        y="92"
                                                                                                                        textAnchor="middle"
                                                                                                                        fontSize="38"
                                                                                                                        fontWeight="800"
                                                                                                                        fill="white"
                                                                                                >
                                                                                                                        {Math.round(
                                                                                                                                                score
                                                                                                                        )}
                                                                                                </text>
                                                                                                <text
                                                                                                                        x="100"
                                                                                                                        y="116"
                                                                                                                        textAnchor="middle"
                                                                                                                        fontSize="13"
                                                                                                                        fill="rgba(255,255,255,0.5)"
                                                                                                >
                                                                                                                        /
                                                                                                                        100
                                                                                                </text>
                                                                                                {/* Grade */}
                                                                                                <text
                                                                                                                        x="100"
                                                                                                                        y="138"
                                                                                                                        textAnchor="middle"
                                                                                                                        fontSize="22"
                                                                                                                        fontWeight="700"
                                                                                                                        fill={
                                                                                                                                                color
                                                                                                                        }
                                                                                                >
                                                                                                                        Grade{' '}
                                                                                                                        {
                                                                                                                                                grade
                                                                                                                        }
                                                                                                </text>
                                                                        </svg>
                                                </div>
                        );
}

